import React, { useState, useRef, useCallback } from 'react';
import axios from 'axios';

// ─── SVG Circular Progress Ring ───────────────────────────────────────────────
// size: ring diameter in px | status: queued|uploading|processing|completed|failed
function CircleRing({ status }) {
  const r  = 16;          // radius
  const cx = 20;          // center
  const stroke = 3;
  const circ = 2 * Math.PI * r; // circumference ≈ 100.5

  const map = {
    queued:     { dash: 0,     color: '#3a3a5c', spin: false, icon: null },
    uploading:  { dash: circ * 0.4, color: '#43e5f7', spin: true,  icon: null },
    processing: { dash: circ * 0.65, color: '#6c63ff', spin: true,  icon: null },
    completed:  { dash: circ,  color: '#1db954', spin: false, icon: '✓' },
    failed:     { dash: circ,  color: '#e74c5e', spin: false, icon: '✕' },
  };
  const cfg = map[status] || map.queued;

  return (
    <svg width="40" height="40" viewBox="0 0 40 40" className="ring-svg">
      {/* background track */}
      <circle cx={cx} cy={cx} r={r} fill="none" stroke="#1c1c3a" strokeWidth={stroke} />
      {/* progress arc */}
      <circle
        cx={cx} cy={cx} r={r}
        fill="none"
        stroke={cfg.color}
        strokeWidth={stroke}
        strokeLinecap="round"
        strokeDasharray={`${cfg.dash} ${circ}`}
        strokeDashoffset={0}
        transform={`rotate(-90 ${cx} ${cx})`}
        className={cfg.spin ? 'ring-spin' : ''}
        style={{ transition: 'stroke-dasharray 0.5s ease' }}
      />
      {/* centre icon */}
      {cfg.icon && (
        <text
          x={cx} y={cx + 5}
          textAnchor="middle"
          fontSize="11"
          fontWeight="700"
          fill={cfg.color}
        >
          {cfg.icon}
        </text>
      )}
    </svg>
  );
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
const fmtBytes = b => {
  if (!b) return '0 B';
  const k = 1024, u = ['B','KB','MB','GB'];
  const i = Math.floor(Math.log(b) / Math.log(k));
  return `${(b / Math.pow(k, i)).toFixed(1)} ${u[i]}`;
};
const uid = () => Math.random().toString(36).slice(2);

const STATUS_LABEL = {
  queued:     'Queued',
  uploading:  'Uploading…',
  processing: 'Converting…',
  completed:  'Done',
  failed:     'Failed',
};

// ─────────────────────────────────────────────────────────────────────────────
export default function App() {
  const inputRef = useRef(null);
  const [files, setFiles]               = useState([]);
  const [uploadPct, setUploadPct]       = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [dragOver, setDragOver]         = useState(false);

  const total     = files.length;
  const completed = files.filter(f => f.status === 'completed').length;
  const failed    = files.filter(f => f.status === 'failed').length;
  const progress  = total === 0 ? 0 : Math.round((completed + failed) / total * 100);

  // ── Add files ────────────────────────────────────────────────────────────
  const addFiles = useCallback(incoming => {
    const valid   = [...incoming].filter(f => f.name.toLowerCase().endsWith('.m4a'));
    const skipped = incoming.length - valid.length;
    if (skipped > 0) alert(`${skipped} file(s) skipped — only .m4a accepted.`);
    if (!valid.length) return;
    setFiles(prev => [
      ...prev,
      ...valid.map(f => ({ id: uid(), name: f.name, size: f.size,
                           status: 'queued', downloadUrl: null, error: null, _file: f })),
    ]);
  }, []);

  const onDrop = e => { e.preventDefault(); setDragOver(false); addFiles(e.dataTransfer.files); };
  const removeFile = id => { if (!isSubmitting) setFiles(p => p.filter(f => f.id !== id)); };
  const clearAll   = () => { if (!isSubmitting) { setFiles([]); setUploadPct(0); if (inputRef.current) inputRef.current.value = ''; } };

  // ── Convert ──────────────────────────────────────────────────────────────
  const handleConvert = async () => {
    const queued = files.filter(f => f.status === 'queued');
    if (!queued.length) return;

    setIsSubmitting(true);
    setUploadPct(0);
    setFiles(p => p.map(f => f.status === 'queued' ? { ...f, status: 'uploading' } : f));

    const form = new FormData();
    queued.forEach(f => form.append('files', f._file));

    try {
      const { data } = await axios.post('/convert', form, {
        headers: { 'Content-Type': 'multipart/form-data' },
        onUploadProgress: e => {
          const pct = e.total ? Math.round(e.loaded / e.total * 100) : 0;
          setUploadPct(pct);
          if (pct === 100)
            setFiles(p => p.map(f => f.status === 'uploading' ? { ...f, status: 'processing' } : f));
        },
      });

      setFiles(p => p.map(localFile => {
        const match = data.conversions.find(r => r.file === localFile.name);
        if (!match) return localFile;
        return { ...localFile, status: match.status,
                 downloadUrl: match.download_url || null, error: match.error || null };
      }));
    } catch (err) {
      const msg = err.response?.data?.error || err.message;
      setFiles(p => p.map(f =>
        ['uploading','processing'].includes(f.status)
          ? { ...f, status: 'failed', error: msg } : f
      ));
    } finally {
      setIsSubmitting(false);
    }
  };

  // ─────────────────────────────────────────────────────────────────────────
  return (
    <div className="app">
      {/* Header */}
      <header className="header">
        <div className="logo">
          <span className="logo-icon">🎵</span>
          <div>
            <h1>M4A → MP3</h1>
            <p>Professional batch audio converter</p>
          </div>
        </div>
        <div className="header-stats">
          <span className="stat"><b>{total}</b> selected</span>
          <span className="stat s-done"><b>{completed}</b> done</span>
          {failed > 0 && <span className="stat s-fail"><b>{failed}</b> failed</span>}
        </div>
      </header>

      {/* Drop zone */}
      <div
        className={`drop-zone ${dragOver ? 'active' : ''}`}
        onClick={() => !isSubmitting && inputRef.current.click()}
        onDragOver={e => { e.preventDefault(); setDragOver(true); }}
        onDragLeave={() => setDragOver(false)}
        onDrop={onDrop}
      >
        <div className="drop-icon">📂</div>
        <p className="drop-title">Drop your .m4a files here</p>
        <p className="drop-sub">or click to browse — up to 50 files, 300 MB each</p>
        <input ref={inputRef} type="file" multiple accept=".m4a"
               style={{ display:'none' }} onChange={e => addFiles(e.target.files)} />
      </div>

      {/* Buttons */}
      {total > 0 && (
        <div className="action-bar">
          <button className="btn btn-primary" onClick={handleConvert}
                  disabled={isSubmitting || !files.some(f => f.status === 'queued')}>
            {isSubmitting ? 'Converting…' : `Convert ${files.filter(f=>f.status==='queued').length} file(s)`}
          </button>
          <button className="btn btn-ghost" onClick={clearAll} disabled={isSubmitting}>Clear All</button>
        </div>
      )}

      {/* Upload progress bar */}
      {isSubmitting && (
        <div className="progress-wrap">
          <div className="progress-labels"><span>Uploading to server…</span><span>{uploadPct}%</span></div>
          <div className="progress-track">
            <div className="progress-fill upload-fill" style={{ width: `${uploadPct}%` }} />
          </div>
        </div>
      )}

      {/* Overall progress bar */}
      {total > 0 && (
        <div className="progress-wrap">
          <div className="progress-labels">
            <span>Overall conversion</span>
            <span>{completed + failed} / {total}</span>
          </div>
          <div className="progress-track">
            <div className="progress-fill" style={{
              width: `${progress}%`,
              background: failed > 0
                ? 'linear-gradient(90deg,#6c63ff,#e74c5e)'
                : 'linear-gradient(90deg,#6c63ff,#43e5f7)',
            }} />
          </div>
        </div>
      )}

      {/* File table */}
      {total > 0 && (
        <div className="table-wrap">
          <table className="file-table">
            <thead>
              <tr>
                <th style={{width:52}}>#</th>
                <th style={{width:44}}>⬤</th>
                <th>File Name</th>
                <th style={{width:80}}>Size</th>
                <th style={{width:110}}>Status</th>
                <th style={{width:110}}>Action</th>
              </tr>
            </thead>
            <tbody>
              {files.map((f, i) => (
                <tr key={f.id} className={f.status === 'completed' ? 'row-done' : f.status === 'failed' ? 'row-fail' : ''}>
                  <td className="td-num">{i + 1}</td>
                  <td className="td-ring"><CircleRing status={f.status} /></td>
                  <td className="td-name" title={f.name}>
                    {f.name}
                    {f.error && <span className="err-tip" title={f.error}> ⚠</span>}
                  </td>
                  <td className="td-size">{fmtBytes(f.size)}</td>
                  <td>
                    <span className={`chip chip-${f.status}`}>
                      {STATUS_LABEL[f.status] || f.status}
                    </span>
                  </td>
                  <td>
                    {f.status === 'completed' && f.downloadUrl
                      ? <a className="btn btn-sm btn-download" href={f.downloadUrl} download target="_blank" rel="noreferrer">⬇ Download</a>
                      : f.status === 'queued'
                      ? <button className="btn btn-sm btn-remove" onClick={() => removeFile(f.id)}>✕ Remove</button>
                      : '—'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {total === 0 && (
        <div className="empty-state">
          <p>No files selected yet. Add some .m4a files to get started.</p>
        </div>
      )}

      <footer className="footer">
        Converted files are automatically deleted after 1 hour &nbsp;·&nbsp; Max 50 files per batch
      </footer>
    </div>
  );
}
